import React, { useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { apiRequest } from '../api/client';

const initialRecipient = {
  primary_disease: '',
  diagnosis_date: '2022-01-01',
  surgery_needed_date: '2026-05-01',
  hospital_name: '',
  hospital_contact_phone: '',
  doctor_name: '',
  doctor_phone: '',
  doctor_registration_number: '',
  matching_criteria: {
    urgency: 'CRITICAL',
  },
  profile: {
    first_name: '',
    last_name: '',
    date_of_birth: '1995-01-01',
    gender: 'OTHER',
    address: '',
    city: '',
    state: '',
    postal_code: '',
    country: 'India',
    latitude: '19.0596',
    longitude: '72.8295',
    blood_group: 'AB+',
    emergency_contact_name: '',
    emergency_contact_phone: '',
  },
};

const initialRequest = {
  request_type: 'BLOOD',
  blood_group_needed: 'AB+',
  organ_type_needed: 'KIDNEY',
  quantity_needed: '1',
  urgency_level: 'CRITICAL',
  needed_by: '',
  hospital_name: '',
  receiving_doctor_name: '',
  receiving_doctor_phone: '',
  hospital_location: {
    latitude: '19.0596',
    longitude: '72.8295',
    address: '',
  },
  clinical_notes: '',
  required_tests: 'CBC',
  is_public: true,
};

const quickApplyItems = [
  {
    id: 'blood-o-plus-critical',
    title: 'Critical O+ Blood Support',
    request_type: 'BLOOD',
    blood_group_needed: 'O+',
    quantity_needed: 2,
    urgency_level: 'CRITICAL',
    hospital_name: 'Metro Care Hospital',
    hospital_address: 'Andheri East, Mumbai',
    receiving_doctor_name: 'Dr. Mehta',
    receiving_doctor_phone: '+919811112222',
    clinical_notes: 'Urgent transfusion support needed in ICU.',
    required_tests: ['CBC', 'Crossmatch'],
    days_until_needed: 1,
  },
  {
    id: 'blood-a-plus-medium',
    title: 'A+ Scheduled Surgery Blood Need',
    request_type: 'BLOOD',
    blood_group_needed: 'A+',
    quantity_needed: 1,
    urgency_level: 'MEDIUM',
    hospital_name: 'City Health Hospital',
    hospital_address: 'Bandra East, Mumbai',
    receiving_doctor_name: 'Dr. Shah',
    receiving_doctor_phone: '+919844445555',
    clinical_notes: 'Pre-surgery blood reservation required.',
    required_tests: ['CBC'],
    days_until_needed: 3,
  },
  {
    id: 'organ-kidney-critical',
    title: 'Kidney Transplant Priority Case',
    request_type: 'ORGAN',
    organ_type_needed: 'KIDNEY',
    quantity_needed: 1,
    urgency_level: 'CRITICAL',
    hospital_name: 'Lifeline Transplant Center',
    hospital_address: 'Dadar, Mumbai',
    receiving_doctor_name: 'Dr. Rao',
    receiving_doctor_phone: '+919833334444',
    clinical_notes: 'Transplant clearance complete. Requires urgent donor match.',
    required_tests: ['HLA Typing', 'Creatinine'],
    days_until_needed: 2,
  },
];

function addDaysToIso(days) {
  const dt = new Date();
  dt.setDate(dt.getDate() + days);
  return dt.toISOString();
}

function RecipientPage() {
  const { token, setFlash } = useAuth();

  const [recipient, setRecipient] = useState(initialRecipient);
  const [requestForm, setRequestForm] = useState(initialRequest);
  const [requests, setRequests] = useState([]);
  const [matches, setMatches] = useState([]);

  function userFacingRequestStatus(status) {
    if (status === 'OPEN') {
      return 'PENDING_ADMIN_REVIEW';
    }
    if (status === 'IN_PROGRESS') {
      return 'ACCEPTED_BY_ADMIN';
    }
    if (status === 'CANCELLED') {
      return 'REJECTED_BY_ADMIN';
    }
    return status || '-';
  }

  function updateRecipientProfile(field, value) {
    setRecipient((prev) => ({
      ...prev,
      profile: {
        ...prev.profile,
        [field]: value,
      },
    }));
  }

  async function createRecipient(event) {
    event.preventDefault();
    try {
      const payload = {
        ...recipient,
        profile: {
          ...recipient.profile,
          latitude: Number(recipient.profile.latitude),
          longitude: Number(recipient.profile.longitude),
        },
      };

      await apiRequest('/recipients/register', {
        method: 'POST',
        token,
        body: payload,
      });

      setFlash({ type: 'success', text: 'Recipient profile created successfully.' });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function createRequest(event) {
    event.preventDefault();

    const payload = {
      request_type: requestForm.request_type,
      blood_group_needed: requestForm.request_type === 'BLOOD' ? requestForm.blood_group_needed : undefined,
      organ_type_needed: requestForm.request_type === 'ORGAN' ? requestForm.organ_type_needed : undefined,
      quantity_needed: Number(requestForm.quantity_needed),
      urgency_level: requestForm.urgency_level,
      needed_by: new Date(requestForm.needed_by).toISOString(),
      hospital_name: requestForm.hospital_name,
      receiving_doctor_name: requestForm.receiving_doctor_name,
      receiving_doctor_phone: requestForm.receiving_doctor_phone,
      hospital_location: {
        latitude: Number(requestForm.hospital_location.latitude),
        longitude: Number(requestForm.hospital_location.longitude),
        address: requestForm.hospital_location.address,
      },
      clinical_notes: requestForm.clinical_notes,
      required_tests: requestForm.required_tests
        .split(',')
        .map((x) => x.trim())
        .filter(Boolean),
      is_public: requestForm.is_public,
    };

    await submitRequest(payload, 'Request applied successfully.');
  }

  async function submitRequest(payload, successPrefix = 'Request applied successfully.') {
    try {
      const data = await apiRequest('/requests', {
        method: 'POST',
        token,
        body: payload,
      });
      setFlash({
        type: 'success',
        text: `${successPrefix} Admin review pending. Current status: ${userFacingRequestStatus(data.request.status)}`,
      });
      await loadRequests();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function applyQuickItem(item) {
    const payload = {
      request_type: item.request_type,
      blood_group_needed: item.request_type === 'BLOOD' ? item.blood_group_needed : undefined,
      organ_type_needed: item.request_type === 'ORGAN' ? item.organ_type_needed : undefined,
      quantity_needed: Number(item.quantity_needed || 1),
      urgency_level: item.urgency_level,
      needed_by: addDaysToIso(item.days_until_needed || 1),
      hospital_name: item.hospital_name || recipient.hospital_name || 'Metro Care Hospital',
      receiving_doctor_name: item.receiving_doctor_name || recipient.doctor_name || 'Dr. Demo',
      receiving_doctor_phone: item.receiving_doctor_phone || recipient.doctor_phone || '+919800000000',
      hospital_location: {
        latitude: Number(recipient.profile.latitude || requestForm.hospital_location.latitude || 19.0596),
        longitude: Number(recipient.profile.longitude || requestForm.hospital_location.longitude || 72.8295),
        address: item.hospital_address || requestForm.hospital_location.address || recipient.profile.address || 'Mumbai',
      },
      clinical_notes: item.clinical_notes || '',
      required_tests: item.required_tests || ['CBC'],
      is_public: true,
    };

    await submitRequest(payload, `${item.title} applied.`);
  }

  async function loadRequests() {
    try {
      const data = await apiRequest('/requests', { token });
      setRequests(data.items || []);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadMatches(requestId) {
    try {
      const data = await apiRequest(`/matches/for-request/${requestId}`, { token });
      setMatches(data.items || []);
      setFlash({ type: 'success', text: `Loaded ${data.count || 0} matches.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  return (
    <section className="panel full">
      <h2>Recipient Center</h2>
      <p className="muted-text">
        Maintain recipient records, apply for blood or organ requests, and track admin decisions in your request section.
      </p>

      <div className="list-block">
        <h3>Quick Apply (Dummy Testing Data)</h3>
        <p className="muted-text">
          Use these one-click demo items to test full workflow from recipient apply to admin action.
        </p>
        <div className="feature-grid">
          {quickApplyItems.map((item) => (
            <article key={item.id} className="feature-card">
              <h3>{item.title}</h3>
              <p>
                {item.request_type} | {item.urgency_level} | Qty: {item.quantity_needed}
                {item.blood_group_needed ? ` | Blood: ${item.blood_group_needed}` : ''}
                {item.organ_type_needed ? ` | Organ: ${item.organ_type_needed}` : ''}
              </p>
              <p>Hospital: {item.hospital_name}</p>
              <button type="button" onClick={() => applyQuickItem(item)}>Apply</button>
            </article>
          ))}
        </div>
      </div>

      <div className="split-grid">
        <form onSubmit={createRecipient} className="form-grid">
          <h3>Create Recipient Profile</h3>
          <input placeholder="Primary Disease" value={recipient.primary_disease} onChange={(e) => setRecipient((prev) => ({ ...prev, primary_disease: e.target.value }))} required />
          <input placeholder="Hospital" value={recipient.hospital_name} onChange={(e) => setRecipient((prev) => ({ ...prev, hospital_name: e.target.value }))} required />
          <input placeholder="Doctor Name" value={recipient.doctor_name} onChange={(e) => setRecipient((prev) => ({ ...prev, doctor_name: e.target.value }))} required />
          <input placeholder="Doctor Phone" value={recipient.doctor_phone} onChange={(e) => setRecipient((prev) => ({ ...prev, doctor_phone: e.target.value }))} required />
          <input placeholder="First Name" value={recipient.profile.first_name} onChange={(e) => updateRecipientProfile('first_name', e.target.value)} required />
          <input placeholder="Last Name" value={recipient.profile.last_name} onChange={(e) => updateRecipientProfile('last_name', e.target.value)} required />
          <input placeholder="Address" value={recipient.profile.address} onChange={(e) => updateRecipientProfile('address', e.target.value)} required />
          <input placeholder="City" value={recipient.profile.city} onChange={(e) => updateRecipientProfile('city', e.target.value)} required />
          <input placeholder="State" value={recipient.profile.state} onChange={(e) => updateRecipientProfile('state', e.target.value)} required />
          <button type="submit">Create Recipient Profile</button>
        </form>

        <form onSubmit={createRequest} className="form-grid">
          <h3>Apply for Blood/Organ Request</h3>
          <select value={requestForm.request_type} onChange={(e) => setRequestForm((prev) => ({ ...prev, request_type: e.target.value }))}>
            <option value="BLOOD">BLOOD</option>
            <option value="ORGAN">ORGAN</option>
          </select>
          {requestForm.request_type === 'BLOOD' ? (
            <input placeholder="Blood Group" value={requestForm.blood_group_needed} onChange={(e) => setRequestForm((prev) => ({ ...prev, blood_group_needed: e.target.value }))} required />
          ) : (
            <input placeholder="Organ Type" value={requestForm.organ_type_needed} onChange={(e) => setRequestForm((prev) => ({ ...prev, organ_type_needed: e.target.value }))} required />
          )}
          <input placeholder="Quantity" value={requestForm.quantity_needed} onChange={(e) => setRequestForm((prev) => ({ ...prev, quantity_needed: e.target.value }))} required />
          <input type="datetime-local" value={requestForm.needed_by} onChange={(e) => setRequestForm((prev) => ({ ...prev, needed_by: e.target.value }))} required />
          <input placeholder="Hospital Name" value={requestForm.hospital_name} onChange={(e) => setRequestForm((prev) => ({ ...prev, hospital_name: e.target.value }))} required />
          <input placeholder="Receiving Doctor" value={requestForm.receiving_doctor_name} onChange={(e) => setRequestForm((prev) => ({ ...prev, receiving_doctor_name: e.target.value }))} required />
          <input placeholder="Receiving Doctor Phone" value={requestForm.receiving_doctor_phone} onChange={(e) => setRequestForm((prev) => ({ ...prev, receiving_doctor_phone: e.target.value }))} required />
          <input placeholder="Hospital Address" value={requestForm.hospital_location.address} onChange={(e) => setRequestForm((prev) => ({ ...prev, hospital_location: { ...prev.hospital_location, address: e.target.value } }))} required />
          <button type="submit">Apply Request</button>
        </form>
      </div>

      <div className="tab-row top-space">
        <button onClick={loadRequests}>Load Requests</button>
      </div>

      <div className="list-block">
        <h3>Request List</h3>
        {requests.length === 0 && <p className="muted-text">No requests loaded. Use "Load Requests" after creating one.</p>}
        {requests.map((item) => (
          <div key={item.id} className="list-item multi">
            <div>
              {item.id} | {item.request_type} | {item.urgency_level} | {userFacingRequestStatus(item.status)}
            </div>
            <button onClick={() => loadMatches(item.id)}>Load Matches</button>
          </div>
        ))}
      </div>

      <div className="list-block">
        <h3>Matches</h3>
        {matches.length === 0 && <p className="muted-text">No matches displayed yet. Select a request and click "Load Matches".</p>}
        {matches.map((match) => (
          <div key={match.match_id} className="list-item">
            <div>{match.match_id}</div>
            <div>{match.donor_name}</div>
            <div>{match.compatibility_score}</div>
            <div>{match.distance_km} km</div>
          </div>
        ))}
      </div>
    </section>
  );
}

export default RecipientPage;
